// ── Micro bloc éditable ──────────────────────────────────────────────────────
function Block({ label, value, onDelete, onChange }) {
  const [editing, setEditing] = useState(false);
  const [val, setVal] = useState(value);

  const save = () => { onChange(val); setEditing(false); };

  return (
    <div className="group flex items-start gap-2 bg-white border border-gray-100 rounded-xl px-3 py-2 shadow-sm hover:shadow transition">
      {editing ? (
        <>
          <input
            className="flex-1 text-sm border-b border-blue-400 outline-none bg-transparent"
            value={val}
            onChange={e => setVal(e.target.value)}
            onKeyDown={e => e.key === 'Enter' && save()}
            autoFocus
          />
          <button onClick={save} className="text-green-600 text-xs font-medium">✓</button>
          <button onClick={() => setEditing(false)} className="text-gray-400 text-xs">✕</button>
        </>
      ) : (
        <>
          <div className="flex-1">
            {label && <p className="text-xs text-gray-400 mb-0.5">{label}</p>}
            <p className="text-sm text-gray-800 font-medium">{value}</p>
          </div>
          <div className="hidden group-hover:flex gap-1">
            <button onClick={() => setEditing(true)} className="text-blue-400 hover:text-blue-600 text-xs">✏️</button>
            <button onClick={onDelete} className="text-red-400 hover:text-red-600 text-xs">🗑️</button>
          </div>
        </>
      )}
    </div>
  );
}

// ── Section avec titre ───────────────────────────────────────────────────────
function Section({ title, children }) {
  return (
    <div className="mb-5">
      <h3 className="text-xs font-bold uppercase tracking-widest text-gray-400 mb-2">{title}</h3>
      <div className="flex flex-wrap gap-2">{children}</div>
    </div>
  );
}

export default function ProfileDetail() {
  const { id } = useParams();
  const navigate = useNavigate();
  const [candidate, setCandidate] = useState(null);
  const [profile, setProfile] = useState(null);
  const [chat, setChat] = useState([]);
  const [chatInput, setChatInput] = useState('');
  const [sending, setSending] = useState(false);
  const [saving, setSaving] = useState(false);

  useEffect(() => {
    api.get(`/candidates/${id}`).then(r => {
      setCandidate(r.data);
      setProfile(r.data.profileData || {});
    });
  }, [id]);

  const saveProfile = async (updatedProfile) => {
    setSaving(true);
    await api.put(`/candidates/${id}/profile`, updatedProfile);
    setSaving(false);
  };

  const updateField = (field, value) => {
    const updated = { ...profile, [field]: value };
    setProfile(updated);
    saveProfile(updated);
  };

  const removeFromArray = (field, index) => {
    const arr = [...(profile[field] || [])];
    arr.splice(index, 1);
    updateField(field, arr);
  };

  const updateInArray = (field, index, value) => {
    const arr = [...(profile[field] || [])];
    arr[index] = typeof arr[index] === 'object' ? { ...arr[index], ...value } : value;
    updateField(field, arr);
  };

  const sendChat = async () => {
    if (!chatInput.trim()) return;
    const userMsg = chatInput;
    setChatInput('');
    setChat(prev => [...prev, { role: 'user', text: userMsg }]);
    setSending(true);

    try {
      // Appel direct à Gemini via Spring Boot
      const res = await api.post(`/candidates/${id}/chat`, {
        message: userMsg,
        currentProfile: profile,
      });
      const { reply, updatedProfile } = res.data;
      if (updatedProfile) {
        setProfile(updatedProfile);
        saveProfile(updatedProfile);
      }
      setChat(prev => [...prev, { role: 'assistant', text: reply }]);
    } catch {
      setChat(prev => [...prev, { role: 'assistant', text: "Erreur de communication avec l'IA." }]);
    } finally {
      setSending(false);
    }
  };

  if (!profile) {
    return (
      <div className="flex items-center justify-center h-full">
        <div className="w-10 h-10 border-4 border-blue-500 border-t-transparent rounded-full animate-spin" />
      </div>
    );
  }

  return (
    <div className="h-screen flex flex-col">
      {/* Header */}
      <div className="bg-white border-b border-gray-100 px-6 py-4 flex items-center gap-4">
        <button onClick={() => navigate('/profiles')} className="text-gray-400 hover:text-gray-700">← Retour</button>
        <h1 className="text-lg font-bold text-gray-900 flex-1">{candidate?.nom}</h1>
        {saving && <span className="text-xs text-gray-400 animate-pulse">Sauvegarde…</span>}
        <button
          onClick={() => navigate(`/transformation?id=${id}`)}
          className="bg-blue-600 text-white px-4 py-2 rounded-lg text-sm font-medium hover:bg-blue-700 transition"
        >
          ✨ Transformer le CV
        </button>
      </div>

      {/* 3 colonnes */}
      <div className="flex flex-1 overflow-hidden">

        {/* Colonne 1 : CV original */}
        <div className="w-1/3 border-r border-gray-100 bg-gray-50 flex flex-col">
          <p className="text-xs font-semibold text-gray-500 px-4 py-3 border-b border-gray-100 uppercase tracking-wider">CV Original</p>
          <div className="flex-1 p-4">
            {candidate?.cvOriginalPath ? (
              <iframe
                src={`http://localhost:8080/api/candidates/${id}/cv-preview`}
                className="w-full h-full rounded-xl border border-gray-200"
                title="CV Preview"
              />
            ) : (
              <div className="flex items-center justify-center h-full text-gray-300 text-center">
                <div>
                  <p className="text-4xl mb-2">📄</p>
                  <p className="text-sm">Aperçu non disponible</p>
                </div>
              </div>
            )}
          </div>
        </div>

        {/* Colonne 2 : Blocs éditables */}
        <div className="w-1/3 border-r border-gray-100 overflow-y-auto p-5">
          <p className="text-xs font-semibold text-gray-500 mb-4 uppercase tracking-wider">Informations extraites</p>

          {/* Nom */}
          <Section title="Identité">
            <Block
              label="Nom complet"
              value={profile.nom_candidat || ''}
              onChange={v => updateField('nom_candidat', v)}
              onDelete={() => updateField('nom_candidat', '')}
            />
            <Block
              label="Titre"
              value={profile.title || ''}
              onChange={v => updateField('title', v)}
              onDelete={() => updateField('title', '')}
            />
            {profile.experience_years && (
              <Block
                label="Années d'expérience"
                value={`${profile.experience_years} ans`}
                onChange={v => updateField('experience_years', parseInt(v))}
                onDelete={() => updateField('experience_years', null)}
              />
            )}
          </Section>

          {/* Compétences */}
          <Section title="Compétences Techniques">
            {(profile.skills || []).map((skill, i) => (
              <Block key={i} value={skill}
                onChange={v => updateInArray('skills', i, v)}
                onDelete={() => removeFromArray('skills', i)} />
            ))}
          </Section>

          {/* Compétences spécifiques */}
          <Section title="Compétences Spécifiques">
            {(profile.specific_skills || []).map((s, i) => (
              <Block key={i} value={s}
                onChange={v => updateInArray('specific_skills', i, v)}
                onDelete={() => removeFromArray('specific_skills', i)} />
            ))}
          </Section>

          {/* Langues */}
          <Section title="Langues">
            {(profile.languages || []).map((l, i) => (
              <Block key={i} label={l.name} value={l.level}
                onChange={v => updateInArray('languages', i, { ...l, level: v })}
                onDelete={() => removeFromArray('languages', i)} />
            ))}
          </Section>

          {/* Formation */}
          <Section title="Formation">
            {(profile.education || []).map((e, i) => (
              <Block key={i}
                label={`${e.year || ''} — ${e.school}`}
                value={e.degree}
                onChange={v => updateInArray('education', i, { ...e, degree: v })}
                onDelete={() => removeFromArray('education', i)} />
            ))}
          </Section>

          {/* Expériences */}
          <div className="mb-5">
            <h3 className="text-xs font-bold uppercase tracking-widest text-gray-400 mb-2">Expériences</h3>
            {(profile.experiences || []).map((exp, i) => (
              <div key={i} className="bg-white border border-gray-100 rounded-xl p-3 mb-2 shadow-sm">
                <div className="flex justify-between items-start mb-1">
                  <p className="text-sm font-semibold text-gray-800">{exp.company}</p>
                  <button onClick={() => removeFromArray('experiences', i)} className="text-red-400 hover:text-red-600 text-xs">🗑️</button>
                </div>
                <p className="text-xs text-blue-600">{exp.position}</p>
                <p className="text-xs text-gray-400 mt-0.5">{exp.start_date} — {exp.end_date || 'présent'}</p>
                <p className="text-xs text-gray-600 mt-1 line-clamp-2">{exp.description}</p>
                {exp.tech_stack && (
                  <p className="text-xs text-gray-400 mt-1">🛠 {exp.tech_stack}</p>
                )}
              </div>
            ))}
          </div>
        </div>

        {/* Colonne 3 : Chatbot */}
        <div className="w-1/3 flex flex-col bg-white">
          <p className="text-xs font-semibold text-gray-500 px-4 py-3 border-b border-gray-100 uppercase tracking-wider">Assistant IA</p>

          <div className="flex-1 overflow-y-auto p-4 space-y-3">
            {chat.length === 0 && (
              <div className="text-center text-gray-300 pt-12">
                <p className="text-3xl mb-2">💬</p>
                <p className="text-sm">Posez une question ou demandez une modification</p>
                <div className="mt-4 space-y-2">
                  {[
                    "Ajoute Java dans les compétences",
                    "Rends ce CV anonyme",
                    "Traduis la description en anglais",
                  ].map(hint => (
                    <button key={hint} onClick={() => setChatInput(hint)}
                      className="block w-full text-left text-xs bg-gray-50 hover:bg-gray-100 border border-gray-100 rounded-lg px-3 py-2 text-gray-500 transition">
                      {hint}
                    </button>
                  ))}
                </div>
              </div>
            )}
            {chat.map((msg, i) => (
              <div key={i} className={`flex ${msg.role === 'user' ? 'justify-end' : 'justify-start'}`}>
                <div className={`max-w-[85%] px-3 py-2 rounded-xl text-sm ${
                  msg.role === 'user' ? 'bg-blue-600 text-white' : 'bg-gray-100 text-gray-800'
                }`}>
                  {msg.text}
                </div>
              </div>
            ))}
            {sending && (
              <div className="flex justify-start">
                <div className="bg-gray-100 px-3 py-2 rounded-xl text-sm text-gray-400 animate-pulse">Réflexion…</div>
              </div>
            )}
          </div>

          <div className="p-3 border-t border-gray-100">
            <div className="flex gap-2">
              <input
                className="flex-1 border border-gray-200 rounded-xl px-3 py-2 text-sm outline-none focus:border-blue-400"
                placeholder="Demandez une modification…"
                value={chatInput}
                onChange={e => setChatInput(e.target.value)}
                onKeyDown={e => e.key === 'Enter' && sendChat()}
              />
              <button
                onClick={sendChat}
                disabled={sending || !chatInput.trim()}
                className="bg-blue-600 text-white px-4 py-2 rounded-xl text-sm font-medium hover:bg-blue-700 disabled:opacity-40 transition"
              >
                →
              </button>
            </div>
          </div>
        </div>
      </div>
    </div>
  );
}
